// Bundles the structure-call-ar specialist (identity + rules + reference + examples)
// into a single TS module so the /api/verdict route ships a self-contained system
// prompt — no runtime fs, no Vercel file-tracing config. Re-run when the specialist
// markdown changes:  node scripts/build-specialist.mjs
//
// ponytail: generated file is committed; this script is the regen tool, NOT a prebuild
// step (Vercel root is landing/ and the sibling specialist folder isn't deployed there).

import { readFileSync, readdirSync, writeFileSync, existsSync } from "node:fs";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const here = dirname(fileURLToPath(import.meta.url));

// The specialist folder is a sibling of launch-layer/ in the working tree and of
// landing/ in the public repo — try both.
const candidates = [
  join(here, "../../../structure-call-ar"), // launch-layer/landing/scripts → comp-8/structure-call-ar
  join(here, "../../structure-call-ar"), // public repo: landing/scripts → structure-call-ar
];
const root = candidates.find((p) => existsSync(join(p, "rules.md")));
if (!root) {
  console.error("structure-call-ar/ not found. Tried:\n" + candidates.join("\n"));
  process.exit(1);
}

const read = (rel) => readFileSync(join(root, rel), "utf8").trim();

const PREAMBLE = `You are \`structure-call-ar\`, an Argentine fiscal-structure specialist, running as a live demo embedded in a public web page. A visitor pastes their situation; you respond with exactly one structured output following the contract below.

Hard rules (non-negotiable):
- Never invent a figure that is not in the reference tables. If the reference lacks a number, say so and do not guess.
- Never output Confidence HIGH on a complex choice (jumping to RI, forming an SAS). HIGH is only for a deterministic trigger.
- A verdict ALWAYS includes the mandatory escalation section ("Trigger de Escalación al Contador" / "Contador Escalation Trigger").
- Run the intake gate first. If 4+ of the 6 structural inputs are missing, REFUSE and ask for them (do not compute a verdict).
- Detect the visitor's input language and respond entirely in it (Spanish input → Spanish; English input → English).
- Figures are calibrated to junio 2026 (BNA comprador ≈ $1.430/USD); tag every USD↔ARS line "(calibrado jun-2026, recalcular contra el BNA del día)".

Below are your identity, your rules, your reference data, and five worked examples. Reproduce that exact format, figure discipline, and language contract.`;

const refDir = join(root, "reference");
const refFiles = existsSync(refDir)
  ? readdirSync(refDir).filter((f) => f.endsWith(".md")).sort()
  : [];

const parts = [
  PREAMBLE,
  "# ===== IDENTITY =====\n\n" + read("identity.md"),
  "# ===== RULES (the contract) =====\n\n" + read("rules.md"),
  "# ===== REFERENCE DATA (figures you read and apply — never invent) =====\n\n" +
    refFiles.map((f) => read(join("reference", f))).join("\n\n---\n\n"),
  "# ===== WORKED EXAMPLES (reproduce this exact format, figure discipline, and language contract) =====\n\n" +
    read("examples.md"),
];

const system = parts.join("\n\n\n");

const out = `// AUTO-GENERATED by scripts/build-specialist.mjs — do not edit by hand.
// Source of truth: ../structure-call-ar/{identity,rules}.md, reference/*.md, examples.md
// Re-run \`node scripts/build-specialist.mjs\` after changing the specialist.

export const SPECIALIST_SYSTEM = ${JSON.stringify(system)};
`;

const dest = join(here, "../lib/specialist-content.ts");
writeFileSync(dest, out, "utf8");
console.log(
  `wrote ${dest} — ${system.length} chars from ${refFiles.length} reference files`
);
